    public static async Task ApplyAsync(SqliteConnection connection, CancellationToken cancellationToken)
    {
        if (await ExistsAsync(connection, "CoreDocuments", cancellationToken))
        {
            var count = Convert.ToInt64(await ScalarAsync(connection, "SELECT COUNT(*) FROM CoreDocuments", cancellationToken));
            if (count > 0)
                throw new InvalidOperationException("数据库包含 CoreDocuments 数据，当前关系存储未实现该数据的安全迁移；已停止启动以保护数据。");
        }

        await using var transaction = (SqliteTransaction)await connection.BeginTransactionAsync(cancellationToken);
        try
        {
            foreach (var encoded in LegacySchemas)
                await ExecuteAsync(connection, transaction, Decode(encoded).Replace("CREATE TABLE ", "CREATE TABLE IF NOT EXISTS ", StringComparison.Ordinal), cancellationToken);
            await ExecuteAsync(connection, transaction, """
                CREATE TABLE IF NOT EXISTS AppSettings (Id INTEGER PRIMARY KEY AUTOINCREMENT, Key TEXT NOT NULL UNIQUE, Value TEXT NOT NULL, UpdatedAt TEXT NOT NULL);
                CREATE TABLE IF NOT EXISTS ChatMessages (Id INTEGER PRIMARY KEY AUTOINCREMENT, ConversationId TEXT NOT NULL, Role TEXT NOT NULL, Content TEXT NOT NULL, CharacterId TEXT NOT NULL DEFAULT '', ModelName TEXT NOT NULL DEFAULT '', Source TEXT NOT NULL DEFAULT 'normal_chat', MetadataJson TEXT NOT NULL DEFAULT '', CreatedAt TEXT NOT NULL);
                CREATE INDEX IF NOT EXISTS IX_ChatMessages_ConversationId_Id ON ChatMessages(ConversationId, Id);
                CREATE TABLE IF NOT EXISTS VoiceRoleCards (RoleId TEXT PRIMARY KEY, Name TEXT NOT NULL DEFAULT '', VoiceName TEXT NOT NULL DEFAULT '', RoleTitle TEXT NOT NULL DEFAULT '', CardPath TEXT NOT NULL DEFAULT '', SourceCardJson TEXT NOT NULL DEFAULT '', TemplateCardJson TEXT NOT NULL DEFAULT '', CardSummary TEXT NOT NULL DEFAULT '', CardSchemaVersion TEXT NOT NULL DEFAULT '', TemplateCardSourceHash TEXT NOT NULL DEFAULT '', TemplateCardGenerationStatus TEXT NOT NULL DEFAULT '', TemplateCardGenerationMessage TEXT NOT NULL DEFAULT '', TemplateCardGeneratedAt TEXT NULL, TemplateCardLastAttemptAt TEXT NULL, TemplateCardIterationCount INTEGER NOT NULL DEFAULT 0, PreferredVoiceId TEXT NOT NULL DEFAULT '', ValidationStatus TEXT NOT NULL DEFAULT 'unknown', ValidationMessage TEXT NOT NULL DEFAULT '', LastValidatedAt TEXT NULL, AvatarPath TEXT NOT NULL DEFAULT '', IsEnabled INTEGER NOT NULL DEFAULT 1, CreatedAt TEXT NOT NULL, UpdatedAt TEXT NOT NULL);
                CREATE TABLE IF NOT EXISTS TimerRecords (Id INTEGER PRIMARY KEY AUTOINCREMENT, RecordId TEXT NULL, SavedAt TEXT NOT NULL, Mode INTEGER NOT NULL, DisplayText TEXT NOT NULL DEFAULT '', DurationSeconds INTEGER NOT NULL, Status TEXT NOT NULL DEFAULT 'completed');
                CREATE TABLE IF NOT EXISTS CoreBackgroundTasks (TaskId TEXT PRIMARY KEY, TaskType TEXT NOT NULL, State INTEGER NOT NULL, Progress REAL NOT NULL, Message TEXT NOT NULL, ResultJson TEXT NOT NULL, Error TEXT NOT NULL, CreatedAt TEXT NOT NULL, UpdatedAt TEXT NOT NULL);
                CREATE INDEX IF NOT EXISTS IX_CoreBackgroundTasks_Type_UpdatedAt ON CoreBackgroundTasks(TaskType, UpdatedAt DESC);
                CREATE TABLE IF NOT EXISTS ProactiveTriggerRules (Id INTEGER PRIMARY KEY AUTOINCREMENT, RuleId TEXT NOT NULL, Enabled INTEGER NOT NULL, Event TEXT NOT NULL, ConditionJson TEXT NOT NULL, Priority INTEGER NOT NULL, CooldownSeconds INTEGER NOT NULL, DisturbanceLevel TEXT NOT NULL, AllowTts INTEGER NOT NULL, ActionTag TEXT NOT NULL, TextTemplatesJson TEXT NOT NULL, Source TEXT NOT NULL, CreatedAt TEXT NOT NULL, UpdatedAt TEXT NOT NULL);
                CREATE UNIQUE INDEX IF NOT EXISTS IX_ProactiveTriggerRules_RuleId ON ProactiveTriggerRules(RuleId);
                CREATE TABLE IF NOT EXISTS ProactiveTriggerStates (Id INTEGER PRIMARY KEY AUTOINCREMENT, RuleId TEXT NOT NULL, LastTriggeredAt TEXT NULL, TriggerCount INTEGER NOT NULL, LastResult TEXT NOT NULL, UpdatedAt TEXT NOT NULL);
                CREATE UNIQUE INDEX IF NOT EXISTS IX_ProactiveTriggerStates_RuleId ON ProactiveTriggerStates(RuleId);
                CREATE TABLE IF NOT EXISTS VoiceCacheGenerations (
                    GenerationId TEXT PRIMARY KEY, RoleId TEXT NOT NULL, IntimacyLevel INTEGER NOT NULL,
                    CacheKey TEXT NOT NULL, ContextHash TEXT NOT NULL, CatalogVersion TEXT NOT NULL,
                    Status TEXT NOT NULL, TotalEntries INTEGER NOT NULL, CompletedEntries INTEGER NOT NULL,
                    PeriodStartAt TEXT NOT NULL, PeriodEndAt TEXT NOT NULL, ErrorCode TEXT NOT NULL DEFAULT '',
                    ErrorMessage TEXT NOT NULL DEFAULT '', CreatedAt TEXT NOT NULL, UpdatedAt TEXT NOT NULL);
                CREATE UNIQUE INDEX IF NOT EXISTS UX_VoiceCacheGenerations_Context ON VoiceCacheGenerations(RoleId, IntimacyLevel, CacheKey);
                CREATE INDEX IF NOT EXISTS IX_VoiceCacheGenerations_Status_UpdatedAt ON VoiceCacheGenerations(Status, UpdatedAt);
                """, cancellationToken);

            await AddColumnIfMissingAsync(connection, transaction, "AppSettings", "UpdatedAt", "TEXT NOT NULL DEFAULT '1970-01-01T00:00:00+00:00'", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceRoleCards", "CreatedAt", "TEXT NOT NULL DEFAULT '1970-01-01T00:00:00+00:00'", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceRoleCards", "AvatarPath", "TEXT NOT NULL DEFAULT ''", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "TimerRecords", "RecordId", "TEXT NULL", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceRoleAudioCaches", "GenerationId", "TEXT NOT NULL DEFAULT ''", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceRoleAudioCaches", "ContextHash", "TEXT NOT NULL DEFAULT ''", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceTriggerLogs", "GenerationId", "TEXT NOT NULL DEFAULT ''", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceTriggerLogs", "ContextHash", "TEXT NOT NULL DEFAULT ''", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceTriggerLogs", "HitAreaName", "TEXT NOT NULL DEFAULT ''", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceTriggerLogs", "NormalizedX", "REAL NULL", cancellationToken);
            await AddColumnIfMissingAsync(connection, transaction, "VoiceTriggerLogs", "NormalizedY", "REAL NULL", cancellationToken);
            // Derived cache rows are safe to consolidate before the slot uniqueness constraint is introduced.
            await ExecuteAsync(connection, transaction, """
                DELETE FROM VoiceRoleAudioCaches
                WHERE Id NOT IN (
                  SELECT keep.Id FROM (
                    SELECT Id, ROW_NUMBER() OVER (
                      PARTITION BY RoleId, IntimacyLevel, CacheKey, TriggerId, BodyPart
                      ORDER BY IsEnabled DESC, UpdatedAt DESC, Id DESC) AS row_number
                    FROM VoiceRoleAudioCaches) AS keep WHERE keep.row_number=1);
                CREATE UNIQUE INDEX IF NOT EXISTS UX_VoiceRoleAudioCaches_Slot
                  ON VoiceRoleAudioCaches(RoleId, IntimacyLevel, CacheKey, TriggerId, BodyPart);
                """, cancellationToken);
            await ExecuteAsync(connection, transaction, "CREATE UNIQUE INDEX IF NOT EXISTS IX_AppSettings_Key ON AppSettings(Key); CREATE UNIQUE INDEX IF NOT EXISTS IX_VoiceRoleCards_RoleId ON VoiceRoleCards(RoleId); UPDATE TimerRecords SET RecordId='legacy_timer_' || Id WHERE COALESCE(RecordId,'')=''; CREATE UNIQUE INDEX IF NOT EXISTS IX_TimerRecords_RecordId ON TimerRecords(RecordId);", cancellationToken);
            if (await ExistsAsync(connection, "VoiceRoles", cancellationToken))
                await ExecuteAsync(connection, transaction, "UPDATE VoiceRoleCards SET AvatarPath=COALESCE((SELECT AvatarPath FROM VoiceRoles WHERE VoiceRoles.RoleId=VoiceRoleCards.RoleId LIMIT 1),'') WHERE COALESCE(AvatarPath,'')='';", cancellationToken);
            await ApplyAgentDecisionSettingsMigrationAsync(connection, transaction, cancellationToken);
            await ApplyMusicPlaylistCapabilityMigrationAsync(connection, transaction, cancellationToken);
            await ValidateAsync(connection, transaction, cancellationToken);
            await transaction.CommitAsync(cancellationToken);
        }
        catch
        {
            await transaction.RollbackAsync(CancellationToken.None);
            throw;
        }
    }

    private static string Decode(string value) => System.Text.Encoding.UTF8.GetString(Convert.FromBase64String(value));

    private static async Task ApplyAgentDecisionSettingsMigrationAsync(
        SqliteConnection connection,
        SqliteTransaction transaction,
        CancellationToken cancellationToken)
    {
        const string marker = "migration:agent_decision_settings_v1";
        await using var markerCommand = connection.CreateCommand();
        markerCommand.Transaction = transaction;
        markerCommand.CommandText = "SELECT 1 FROM AppSettings WHERE Key=$key LIMIT 1";
        markerCommand.Parameters.AddWithValue("$key", marker);
        if (await markerCommand.ExecuteScalarAsync(cancellationToken) is not null) return;

        var now = DateTimeOffset.Now.ToString("O");
        await using var command = connection.CreateCommand();
        command.Transaction = transaction;
        command.CommandText = """
            DELETE FROM AgentCapabilities WHERE CapabilityName='live2d.publish';
            UPDATE AgentCapabilities
            SET Description='检查 TTS 服务；服务不可用时启动服务并再次检查。',
                ConfigJson='{"steps":[{"capabilityName":"tts.check_status","args":{},"onSuccess":"stop","onFailure":"continue"},{"capabilityName":"tts.restart","args":{},"onFailure":"stop"},{"capabilityName":"tts.check_status","args":{},"onFailure":"stop"}]}',
                RiskLevel='high', RequireConfirm=1, Enabled=1, UpdatedAt=$now
            WHERE CapabilityName='tts.diagnose';
            UPDATE AgentCapabilities
            SET Description='打开当前 AIMaid 的系统设置窗口。',
                ConfigJson='{"windowType":"settings"}',
                Enabled=1, UpdatedAt=$now
            WHERE CapabilityName='app.open_settings';
            INSERT INTO AppSettings (Key, Value, UpdatedAt) VALUES ($marker, 'applied', $now);
            """;
        command.Parameters.AddWithValue("$marker", marker);
        command.Parameters.AddWithValue("$now", now);
        await command.ExecuteNonQueryAsync(cancellationToken);
    }

    private static async Task ApplyMusicPlaylistCapabilityMigrationAsync(
        SqliteConnection connection,
        SqliteTransaction transaction,
        CancellationToken cancellationToken)
    {
        const string marker = "migration:music_playlist_capability_v1";
        await using var markerCommand = connection.CreateCommand();
        markerCommand.Transaction = transaction;
        markerCommand.CommandText = "SELECT 1 FROM AppSettings WHERE Key=$key LIMIT 1";
        markerCommand.Parameters.AddWithValue("$key", marker);
        if (await markerCommand.ExecuteScalarAsync(cancellationToken) is not null) return;

        var now = DateTimeOffset.Now.ToString("O");
        await using var command = connection.CreateCommand();
        command.Transaction = transaction;
        command.CommandText = """
            UPDATE AgentCapabilities
            SET Description='搜索并播放单曲或有序歌单。单曲使用 songName 和 singerName；用户要求多首、一些歌曲或歌单时，使用 songs 列表，并按期望播放顺序填写。每首歌曲都必须提供真实、具体的歌曲名和歌手名，不得把歌手、风格、情绪或类别词直接当作歌曲名。',
                ArgsSchemaJson='{"type":"object","oneOf":[{"required":["songName","singerName"]},{"required":["songs"]}],"properties":{"songName":{"type":"string","description":"单曲的具体歌曲名"},"singerName":{"type":"string","description":"单曲的歌手名"},"songs":{"type":"array","minItems":1,"maxItems":20,"description":"按播放顺序排列的歌曲列表","items":{"type":"object","required":["songName","singerName"],"properties":{"songName":{"type":"string","description":"具体歌曲名"},"singerName":{"type":"string","description":"歌手名"}},"additionalProperties":false}}},"additionalProperties":false}',
                UpdatedAt=$now
            WHERE CapabilityName='music.search';
            UPDATE LlmSourcePrompts
            SET SystemPromptTemplate=SystemPromptTemplate || char(13) || char(10) || char(13) || char(10) ||
                  '【音乐歌单参数规则】' || char(13) || char(10) ||
                  '调用 music.search 播放单曲时，args 必须同时返回 songName 和 singerName。用户要求多首、一些歌曲或歌单时，args 必须返回 songs 数组；数组按播放顺序排列，每项都必须包含真实、具体的 songName 和 singerName。',
                UpdatedAt=$now
            WHERE SourceKey='agent_decision'
              AND instr(SystemPromptTemplate, '【音乐歌单参数规则】')=0;
            INSERT INTO AppSettings (Key, Value, UpdatedAt) VALUES ($marker, 'applied', $now);
            """;
        command.Parameters.AddWithValue("$marker", marker);
        command.Parameters.AddWithValue("$now", now);
        await command.ExecuteNonQueryAsync(cancellationToken);
    }

    private static async Task ValidateAsync(SqliteConnection connection, SqliteTransaction transaction, CancellationToken cancellationToken)
    {
        var required = new Dictionary<string, string[]>(StringComparer.OrdinalIgnoreCase)
        {
            ["AppSettings"] = ["Key", "Value", "UpdatedAt"],
            ["ChatMessages"] = ["Id", "ConversationId", "Role", "Content", "MetadataJson", "CreatedAt"],
            ["VoiceRoleCards"] = ["RoleId", "CreatedAt", "UpdatedAt"],
            ["TimerRecords"] = ["Id", "RecordId", "SavedAt", "DurationSeconds"],
            ["CoreBackgroundTasks"] = ["TaskId", "TaskType", "UpdatedAt"]
            , ["VoiceCacheGenerations"] = ["GenerationId", "RoleId", "ContextHash", "Status"]
        };
        foreach (var pair in required)
        {
            if (!await ExistsAsync(connection, pair.Key, cancellationToken)) throw new InvalidOperationException($"数据库 Schema 缺少表 {pair.Key}。");
            var columns = await ColumnsAsync(connection, transaction, pair.Key, cancellationToken);
            foreach (var column in pair.Value)
                if (!columns.Contains(column)) throw new InvalidOperationException($"数据库 Schema 缺少列 {pair.Key}.{column}。");
        }
    }

    private static async Task AddColumnIfMissingAsync(SqliteConnection connection, SqliteTransaction transaction, string table, string column, string definition, CancellationToken cancellationToken)
    {
        if ((await ColumnsAsync(connection, transaction, table, cancellationToken)).Contains(column)) return;
        await ExecuteAsync(connection, transaction, $"ALTER TABLE \"{table}\" ADD COLUMN \"{column}\" {definition};", cancellationToken);
    }

    private static async Task<HashSet<string>> ColumnsAsync(SqliteConnection connection, SqliteTransaction transaction, string table, CancellationToken cancellationToken)
    {
        await using var command = connection.CreateCommand(); command.Transaction = transaction; command.CommandText = $"PRAGMA table_info(\"{table}\")";
        var result = new HashSet<string>(StringComparer.OrdinalIgnoreCase); await using var reader = await command.ExecuteReaderAsync(cancellationToken);
        while (await reader.ReadAsync(cancellationToken)) result.Add(reader.GetString(1));
        return result;
    }

    private static async Task<bool> ExistsAsync(SqliteConnection connection, string table, CancellationToken cancellationToken)
    {
        await using var command = connection.CreateCommand(); command.CommandText = "SELECT 1 FROM sqlite_master WHERE type='table' AND name=$name LIMIT 1"; command.Parameters.AddWithValue("$name", table);
        return await command.ExecuteScalarAsync(cancellationToken) is not null;
    }

    private static async Task<object?> ScalarAsync(SqliteConnection connection, string sql, CancellationToken cancellationToken)
    {
        await using var command = connection.CreateCommand(); command.CommandText = sql; return await command.ExecuteScalarAsync(cancellationToken);
    }

    private static async Task ExecuteAsync(SqliteConnection connection, SqliteTransaction transaction, string sql, CancellationToken cancellationToken)
    {
        await using var command = connection.CreateCommand(); command.Transaction = transaction; command.CommandText = sql; await command.ExecuteNonQueryAsync(cancellationToken);
    }
}
